"use client";

import { useEffect, useState } from "react";
import { useParams, useRouter } from "next/navigation";
import { useUser } from "@clerk/nextjs";
import { api, Observation } from "@/lib/api";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { 
  ArrowLeft, 
  Save, 
  Users, 
  Target, 
  ShieldAlert,
  TrendingUp,
  Activity
} from "lucide-react";
import { AnimatedToggle } from "@/components/ui/animated-toggle";
import { Slider } from "@/components/ui/slider";
import { Badge } from "@/components/ui/badge";
import { Progress } from "@/components/ui/progress";
import { AreaChart, Area, XAxis, YAxis, Tooltip, ResponsiveContainer, CartesianGrid } from "recharts";
import { cn } from "@/lib/utils";
import { useEnv } from "@/components/env-provider";

export function FlagDetailClient() {
  const params = useParams();
  const router = useRouter();
  const id = params.id as string;
  const { user } = useUser();
  const isManager = user?.publicMetadata?.role === "Manager";

  
  const { state } = useEnv();
  const [isOn, setIsOn] = useState(true);
  const [rollout, setRollout] = useState([25]);
  const [hasChanges, setHasChanges] = useState(false);
  const [message, setMessage] = useState<string>("");

  useEffect(() => {
    const lastObs = state?.history?.[state.history.length - 1]?.observation;
    if (lastObs && lastObs.feature_name === id) {
      const timeout = setTimeout(() => {
        setIsOn(!(state?.is_done ?? false));
        setRollout([lastObs.current_rollout_percentage]);
        setHasChanges(false);
      }, 0);
      return () => clearTimeout(timeout);
    }
  }, [id, state]);

  const lastObs: Observation | undefined = state?.history?.[state.history.length - 1]?.observation;
  const isBackendFlag = lastObs?.feature_name === id;
  const extra = lastObs?.extra_context as Record<string, unknown> | undefined;
  const patternRisk = Number(extra?.pattern_risk ?? 0);
  const anomaly = extra?.anomaly;
  const anomalyObj = anomaly && typeof anomaly === "object" ? (anomaly as Record<string, unknown>) : undefined;
  const isAnomaly = Boolean(anomalyObj?.is_anomaly);
  const benchmarking = extra?.benchmarking && typeof extra.benchmarking === "object"
    ? (extra.benchmarking as Record<string, unknown>)
    : undefined;

  const handleRolloutChange = (val: number | number[] | readonly number[]) => {
    const newVal = typeof val === 'number' ? val : val[0];
    setRollout([newVal]);
    setHasChanges(true);
  };

  const handleToggle = (state: boolean) => {
    setIsOn(state);
    setHasChanges(true);
  };

  const handleSave = async () => {
    try {
      const targetRollout = rollout[0];
      let action_type = "MAINTAIN";
      if (!isOn) {
        action_type = "ROLLBACK";
      } else if (targetRollout === 100) {
        action_type = "FULL_ROLLOUT";
      } else if (targetRollout === 0) {
        action_type = "HALT_ROLLOUT";
      } else if (targetRollout > (lastObs?.current_rollout_percentage ?? 0)) {
        action_type = "INCREASE_ROLLOUT";
      } else {
        action_type = "DECREASE_ROLLOUT";
      }

      await api.step({
        action_type,
        target_percentage: targetRollout,
        reason: `Manual override via dashboard for ${id}`
      });
      
      setHasChanges(false);
      setMessage("Saved.");
    } catch (error) {
      console.error("Failed to save changes:", error);
      setMessage(error instanceof Error ? error.message : "Save failed");
    }
  };

  const handleApprove = () => {
    setMessage("Feature approved by Manager.");
  };

  return (

    <div className="flex-1 space-y-6 p-8">
      <div className="flex items-center justify-between">
        <div className="flex items-center gap-4">
          <Button variant="ghost" size="icon" onClick={() => router.push("/flags")} className="rounded-full hover:bg-muted">
            <ArrowLeft className="h-5 w-5" />
          </Button>
          <div>
            <div className="flex items-center gap-3">
              <h1 className="text-3xl font-bold tracking-tight capitalize">{id.replace(/-/g, ' ')}</h1>
              <Badge variant={isOn ? "default" : "secondary"} className="rounded-full">
                {isOn ? "Active" : "Inactive"}
              </Badge>
            </div>
            <p className="text-muted-foreground mt-1 text-sm font-mono">{id}</p>
          </div>
        </div>
        
        <div className="flex items-center gap-3">
          <Button 
            disabled={!isManager} 
            onClick={handleApprove} 
            className="rounded-full bg-green-500/20 hover:bg-green-500/30 text-green-500 border border-green-500/50 shadow-md shadow-green-500/10 transition-all font-medium"
          >
            Approve Feature
          </Button>
          {hasChanges && (
            <Button onClick={handleSave} className="rounded-full bg-primary/20 hover:bg-primary/30 text-primary border border-primary/50 shadow-[0_0_15px_rgba(139,92,246,0.3)] transition-all font-medium">
              <Save className="mr-2 h-4 w-4" />
              Save Changes
            </Button>
          )}
        </div>
      </div>

      {message ? (
        <div className={cn(
          "rounded-lg border border-border/50 bg-card/50 px-4 py-3 text-sm",
          message.toLowerCase().includes("fail") ? "text-destructive" : "text-muted-foreground"
        )}>
          {message}
        </div>
      ) : null}

      <div className="grid gap-6 md:grid-cols-3">
        <div className="md:col-span-2 space-y-6">
          {/* Mission Progress Section */}
          {isBackendFlag && lastObs?.mission_name && (
            <Card className="glassy-card border-primary/20 bg-primary/5">
              <CardHeader className="pb-2">
                <div className="flex items-center justify-between">
                  <CardTitle className="text-sm font-bold flex items-center gap-2 text-primary">
                    <Target className="h-4 w-4" />
                    Active Mission: {lastObs.mission_name}
                  </CardTitle>
                  <Badge variant="outline" className="bg-primary/10 border-primary/30 text-primary">
                    Phase {lastObs.phase_index !== undefined ? lastObs.phase_index + 1 : 0}
                  </Badge>
                </div>
              </CardHeader>
              <CardContent className="space-y-4">
                <div className="flex items-center justify-between text-xs mb-1 text-muted-foreground">
                   <span>{lastObs.current_phase}</span>
                   <span>{((lastObs.phase_progress ?? 0) * 100).toFixed(0)}%</span>
                </div>
                <Progress value={(lastObs.phase_progress ?? 0) * 100} className="h-2" />
                <div className="flex flex-wrap gap-2 pt-2">
                   {lastObs.phase_objectives?.map((obj, i) => (
                     <Badge key={i} variant="outline" className="text-[10px] bg-background/50 border-border/50 text-muted-foreground">{obj}</Badge>
                   ))}
                </div>
              </CardContent>
            </Card>
          )}

          <Card className="glassy-card">
            <CardHeader className="flex flex-row items-center justify-between">
              <div>
                <CardTitle>Rollout Control</CardTitle>
                <CardDescription>Manage how this flag is evaluated.</CardDescription>
              </div>
              <AnimatedToggle isOn={isOn} onToggle={handleToggle} />
            </CardHeader>
            <CardContent className="space-y-8">
              <div className="space-y-4">
                <div className="flex items-center justify-between">
                  <span className="text-3xl font-bold text-primary text-glow">{rollout[0]}%</span>
                </div>
                <Slider 
                  value={rollout} 
                  onValueChange={handleRolloutChange} 
                  max={100} 
                  step={1} 
                  disabled={!isOn}
                  className="py-4"
                />
              </div>
            </CardContent>
          </Card>

          <Card className="glassy-card">
            <CardHeader>
              <CardTitle>Agent Thought Stream</CardTitle>
              <CardDescription>Live timeline of AI reasoning and actions.</CardDescription>
            </CardHeader>
            <CardContent>
              {state?.history && state.history.length > 0 ? (
                <div className="space-y-4 max-h-[300px] overflow-y-auto pr-2 custom-scrollbar">
                  {[...state.history].reverse().slice(0, 10).map((h, i) => (
                    <div key={i} className="flex gap-4 border-b border-border/40 pb-4 last:border-0 last:pb-0">
                      <div className="mt-1">
                        <div className="h-2 w-2 rounded-full bg-primary shadow-[0_0_8px_rgba(139,92,246,0.8)]" />
                      </div>
                      <div>
                        <div className="flex items-center justify-between mb-1">
                          <span className="text-xs font-bold text-primary tracking-wide">
                            {String(h.action?.action_type || 'UNKNOWN')} → {String(h.action?.target_percentage || '0')}%
                          </span>
                          <span className="text-[10px] text-muted-foreground">T-{state.history.length - i}</span>
                        </div>
                        <p className="text-xs text-muted-foreground italic leading-relaxed bg-background/30 p-2 rounded-md border border-border/30">
                          &quot;{String(h.action?.reason || 'No reason provided')}&quot;
                        </p>
                      </div>
                    </div>
                  ))}
                </div>
              ) : (
                <div className="py-12 flex flex-col items-center justify-center text-center">
                  <div className="w-12 h-12 rounded-full bg-primary/10 flex items-center justify-center mb-4 pulse-border">
                    <Activity className="h-5 w-5 text-primary animate-pulse" />
                  </div>
                  <p className="text-sm font-medium text-foreground">Awaiting autonomous decisions</p>
                  <p className="text-xs text-muted-foreground mt-1 max-w-xs">The AI agent is still observing baseline traffic before making rollout recommendations.</p>
                </div>
              )}
            </CardContent>
          </Card>
        </div>

        <div className="space-y-6">
          {/* Stakeholder Sentiment Summary */}
          {isBackendFlag && (
             <Card className="glassy-card">
                <CardHeader className="pb-2">
                  <CardTitle className="text-sm font-medium flex items-center gap-2">
                    <Users className="h-4 w-4 text-primary" />
                    Stakeholder Sentiment
                  </CardTitle>
                </CardHeader>
                <CardContent className="space-y-4">
                   {[
                     { name: "DevOps", score: lastObs?.stakeholder_devops_sentiment },
                     { name: "Product", score: lastObs?.stakeholder_product_sentiment },
                     { name: "CS", score: lastObs?.stakeholder_customer_sentiment }
                   ].map(s => (
                     <div key={s.name} className="space-y-1">
                        <div className="flex items-center justify-between text-[10px] uppercase font-bold text-muted-foreground">
                           <span>{s.name}</span>
                           <span className={cn((s.score ?? 0) > 0 ? "text-green-500" : "text-destructive")}>
                             {(s.score ?? 0).toFixed(2)}
                           </span>
                        </div>
                        <Progress value={((s.score ?? 0) + 1) * 50} className={cn("h-1", (s.score ?? 0) < 0 && "[&>div]:bg-destructive")} />
                     </div>
                   ))}
                </CardContent>
             </Card>
          )}

          {/* Session Intelligence Panel */}
          <Card className="glassy-card">
            <CardHeader className="pb-2">
              <CardTitle className="text-sm font-medium flex items-center gap-2">
                <ShieldAlert className="h-4 w-4 text-amber-500" />
                Session Intelligence
              </CardTitle>
            </CardHeader>
            <CardContent className="space-y-5">
              <div className="flex items-center justify-between text-sm">
                <span className="text-muted-foreground">AI Confidence</span>
                <span className="font-bold text-green-500 text-glow">
                  {Math.max(0, 100 - patternRisk * 100).toFixed(0)}%
                </span>
              </div>
              <Progress
                value={Math.max(0, 100 - patternRisk * 100)}
                className="h-1.5 [&>div]:bg-green-500"
              />
              
              <div className="pt-4 border-t border-border/50">
                <div className="flex items-center justify-between text-xs mb-2">
                  <span className="text-muted-foreground font-medium uppercase">Active Anomaly</span>
                  {isAnomaly ? (
                    <Badge variant="destructive" className="h-4 text-[9px] pulse-border">DETECTED</Badge>
                  ) : (
                    <Badge variant="outline" className="h-4 text-[9px] text-green-500 border-green-500/30">CLEAR</Badge>
                  )}
                </div>
              </div>
            </CardContent>
          </Card>

          <Card className="glassy-card">
            <CardHeader className="pb-2">
              <CardTitle className="text-sm font-medium flex items-center gap-2">
                <TrendingUp className="h-4 w-4 text-primary" />
                Benchmark
              </CardTitle>
            </CardHeader>
            <CardContent>
               <div className="text-center py-2">
                  <span className="text-3xl font-bold text-glow">{(Number(benchmarking?.percentile ?? 0) * 100).toFixed(0)}th</span>
                  <p className="text-[10px] text-muted-foreground mt-1">Percentile Performance</p>
               </div>
            </CardContent>
          </Card>
        </div>
      </div>
    </div>
  );
}
